import{_ as a,c as t,o as s,ak as i,ap as r}from"./chunks/framework.BZBtq1Ev.js";const m=JSON.parse('{"title":"AireIdentity Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireidentity-v2-14-0.md","filePath":"aireblock-releases/aireidentity-v2-14-0.md","lastUpdated":1777564046000}'),o={name:"aireblock-releases/aireidentity-v2-14-0.md"};function n(c,e,l,d,u,h){return s(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="aireidentity-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+r+'"> AireIdentity Release Notes</span> <a class="header-anchor" href="#aireidentity-release-notes" aria-label="Permalink to “AireIdentity Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 2.14.0<br><strong>Release Date:</strong> 12 March 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Last Login Time on User Pages (ID-1147)</li><li>Resource Indicator Support via RFC8707 (ID-1158)</li></ul><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="last-login-time-on-user-pages-id-1147" tabindex="-1">Last Login Time on User Pages (ID-1147) <a class="header-anchor" href="#last-login-time-on-user-pages-id-1147" aria-label="Permalink to “Last Login Time on User Pages (ID-1147)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A new &quot;Last Logged In&quot; column has been added to the user pages in AireIdentity, displaying the date and time each user most recently authenticated.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now see at a glance when each user last accessed the platform, making it easier to identify inactive accounts and support licence usage reporting across your organisation.</p></div><h4 id="resource-indicator-support-via-rfc8707-id-1158" tabindex="-1">Resource Indicator Support via RFC8707 (ID-1158) <a class="header-anchor" href="#resource-indicator-support-via-rfc8707-id-1158" aria-label="Permalink to “Resource Indicator Support via RFC8707 (ID-1158)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>AireIdentity now implements RFC8707 Resource Indicators, enabling issued access tokens to be bound to specific resource server URLs (e.g. a particular MCP server endpoint). This ensures that a token obtained for one service cannot be reused against a different one, aligning with the MCP authorisation specification.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Your platform&#39;s authentication is now more secure and better prepared for integrations that require tokens to be scoped to specific services, reducing the risk of token misuse across connected systems.</p></div>',14)])])}const f=a(o,[["render",n]]);export{m as __pageData,f as default};
